import{_ as a,o,c as e,a0 as l}from"./chunks/framework.CSK6mTG2.js";const h=JSON.parse('{"title":"分布式训练全景：数据并行、模型并行、流水线并行","description":"","frontmatter":{"title":"分布式训练全景：数据并行、模型并行、流水线并行","author":"唐超","date":"2026-07-11T00:00:00.000Z"},"headers":[],"relativePath":"menuAI/distributed-training.md","filePath":"menuAI/distributed-training.md"}'),r={name:"menuAI/distributed-training.md"};function i(u,t,n,s,p,q){return o(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="分布式训练全景-数据并行、模型并行、流水线并行" tabindex="-1">分布式训练全景：数据并行、模型并行、流水线并行 <a class="header-anchor" href="#分布式训练全景-数据并行、模型并行、流水线并行" aria-label="Permalink to &quot;分布式训练全景：数据并行、模型并行、流水线并行&quot;">​</a></h1><h2 id="一、为什么一块显卡装不下" tabindex="-1">一、为什么一块显卡装不下？ <a class="header-anchor" href="#一、为什么一块显卡装不下" aria-label="Permalink to &quot;一、为什么一块显卡装不下？&quot;">​</a></h2><p>先说个扎心的事实：今天的大模型，动辄几百亿、上千亿参数。一个参数如果用 FP16 存，占 2 字节。700 亿参数光是存权重就要 1400 亿字节 ≈ 140 GB。这还没算梯度、优化器状态（Adam 那套还要额外 12 字节/参数）。一块 A100 才 80GB 显存。你说一块卡怎么装？</p><p>装不下，就拆。<strong>分布式训练，说白了就是&quot;一群显卡一起干活，把本来一张卡扛不住的活分摊开&quot;。</strong></p><p>打个比方：你要印一本 1000 页的书。一个人印（一张卡）太慢也搬不动，于是你叫来 10 个工友（10 张卡），一起分工。但具体怎么分工，有三种经典套路，这就是今天要讲的：数据并行、模型并行、流水线并行。</p><h2 id="二、数据并行-data-parallelism-同款机器-分活干" tabindex="-1">二、数据并行（Data Parallelism）：同款机器，分活干 <a class="header-anchor" href="#二、数据并行-data-parallelism-同款机器-分活干" aria-label="Permalink to &quot;二、数据并行（Data Parallelism）：同款机器，分活干&quot;">​</a></h2><p>最直觉的分工：10 个人，每人手上都有完整的一本样书（完整模型副本），但每人只印其中 100 页（不同的一批数据）。</p><p>具体流程：</p><ul><li>每张卡都持有完整的模型参数副本</li><li>把训练数据切成 N 份，每张卡吃一份</li><li>各算各的梯度</li><li>关键一步：所有卡把算出来的梯度&quot;汇总平均&quot;，然后各自用同样的平均梯度更新自己的副本</li></ul><p>这样每张卡的模型始终保持一致，但每张卡只处理了 1/N 的数据量，整体训练速度就快了 N 倍（理想情况下）。</p><p>打个比方：10 个厨师，每人都有同一本菜谱（模型），但分别炒不同的菜（数据）。炒完各自总结&quot;哪儿火候过了&quot;（梯度），大家碰头汇总成一份统一的改进方案（梯度同步），然后各自按同一套方案改进自己的菜谱。最后 10 个人的菜谱变成一样的、更好的版本。</p><p><strong>优点</strong>：实现简单，几乎是分布式训练的&quot;默认选项&quot;。 <strong>缺点</strong>：每张卡都要存完整模型，显存省不下来；而且每次都要把梯度在全卡间同步（通信开销大）。数据量能并行，但&quot;模型太大装不下&quot;这个根本问题它解决不了。</p><h2 id="三、模型并行-model-parallelism-把机器拆开" tabindex="-1">三、模型并行（Model Parallelism）：把机器拆开 <a class="header-anchor" href="#三、模型并行-model-parallelism-把机器拆开" aria-label="Permalink to &quot;三、模型并行（Model Parallelism）：把机器拆开&quot;">​</a></h2><p>数据并行解决不了&quot;模型太大一张卡装不下&quot;。那就换思路：不复制模型了，把模型本身切开，分给不同的卡。</p><p>经典做法是&quot;张量并行&quot;（Tensor Parallelism，Megatron-LM 那套）。比如模型某一层有个巨大的矩阵乘法，本来要在一张卡上算，现在把它按列或按行切成几块，每张卡算一块，最后拼起来。</p><p>打个比方：还是印书，但这次不是分页数，而是把一台印刷机拆成几个模块——有人专门管排版、有人专门管上墨、有人专门管装订。每个人手里的只是整台机器的一部分。模型被&quot;横向切开&quot;，每张卡只持有部分权重。</p><p><strong>优点</strong>：能训一张卡根本放不下的超大模型（GPT-3、千问、DeepSeek 都靠它）。 <strong>缺点</strong>：卡与卡之间像流水线工人，必须频繁&quot;交接&quot;中间结果，通信极其密集，对卡间互联（NVLink、IB 网络）要求很高。</p><h2 id="四、流水线并行-pipeline-parallelism-工厂流水线" tabindex="-1">四、流水线并行（Pipeline Parallelism）：工厂流水线 <a class="header-anchor" href="#四、流水线并行-pipeline-parallelism-工厂流水线" aria-label="Permalink to &quot;四、流水线并行（Pipeline Parallelism）：工厂流水线&quot;">​</a></h2><p>流水线并行是模型并行的&quot;竖向切法&quot;：不按层内切，而是按&quot;层&quot;切。第 1~10 层放卡 A，第 11~20 层放卡 B……数据像流水线一样，一层层往下流。</p><p>打个比方：工厂流水线。第一道工序（前几层）在工位 A 做完，传给工位 B 做第二道工序（中间几层），再传给 C。每张卡只持有连续的一部分层。</p><p>但流水线有个经典毛病：<strong>气泡（bubble）</strong>。想象流水线上，第一件产品还在 A 工位时，B、C 只能干等——它们没活干，这段空闲就是&quot;气泡&quot;，浪费算力。解决办法是&quot;微批次&quot;（micro-batch）：把一批数据再切成很多小份，让不同小份在不同工位上同时流动，气泡就被填满了。</p><h2 id="五、三种并行怎么选-——通常是-组合拳" tabindex="-1">五、三种并行怎么选？——通常是&quot;组合拳&quot; <a class="header-anchor" href="#五、三种并行怎么选-——通常是-组合拳" aria-label="Permalink to &quot;五、三种并行怎么选？——通常是&quot;组合拳&quot;&quot;">​</a></h2><p>现实里没人只用一种。比如训练一个超大大模型，典型配置是：</p><ul><li>模型并行（张量并行）解决&quot;单层太宽放不下&quot;</li><li>流水线并行解决&quot;层数太多放不下&quot;</li><li>数据并行解决&quot;数据太多太慢&quot;</li></ul><p>像 DeepSeek-V3 那种规模，就是 8 卡一组的张量并行 + 跨节点的流水线并行 + 多组数据并行，叠在一起。想象一个三维魔方：<strong>X 轴切模型宽度、Y 轴切模型深度、Z 轴切数据。</strong></p><h2 id="六、一个容易混淆的点-zero-优化器状态并行" tabindex="-1">六、一个容易混淆的点：ZeRO / 优化器状态并行 <a class="header-anchor" href="#六、一个容易混淆的点-zero-优化器状态并行" aria-label="Permalink to &quot;六、一个容易混淆的点：ZeRO / 优化器状态并行&quot;">​</a></h2><p>提一句数据并行的进阶版 ZeRO（零冗余优化器）。普通数据并行每张卡都存了完整的优化器状态 + 梯度 + 参数，很浪费。ZeRO 把这些也&quot;切片&quot;分存到各卡，用的时候再聚合。它本质还是数据并行，只是把&quot;副本冗余&quot;也省掉了，显存更省。</p><p>打个比方：普通数据并行像 10 个人每人都背了一整本字典备用；ZeRO 像大家把字典撕成 10 份，每人只带一份，要用哪一页再去问对应的人借。省了 10 倍空间，代价是偶尔要&quot;借页&quot;（通信）。</p><h2 id="七、一句话总结" tabindex="-1">七、一句话总结 <a class="header-anchor" href="#七、一句话总结" aria-label="Permalink to &quot;七、一句话总结&quot;">​</a></h2><p>分布式训练就是&quot;一群显卡分摊装不下的活&quot;。<strong>数据并行</strong>=每人一份完整模型、分数据干、最后同步梯度（简单但省不了显存）；<strong>模型并行/张量并行</strong>=把模型横切开、各卡管一部分（能训超大模型但通信密）；<strong>流水线并行</strong>=按层竖切、像工厂流水线（有气泡浪费，用微批次填）；实战基本是三者组合的&quot;三维魔方&quot;。理解这一层，你看任何大模型的训练新闻，都能看懂它背后在&quot;怎么分工&quot;。</p>',30)])])}const m=a(r,[["render",i]]);export{h as __pageData,m as default};
